// HTML Structure Generator for WordPress Content
// Converts AI-generated content into semantic HTML with SEO optimization

const contentData = $input.item.json;

// Extract content fields from the structured data
const title = contentData.title || 'Untitled Article';
const metaDescription = contentData.metaDescription || contentData.summary || '';
const keywords = contentData.keywords || [];
const content = contentData.content || '';
const sections = contentData.sections || [];
const callToAction = contentData.callToAction || '';
const author = contentData.author || 'Content Team';
const category = contentData.category || 'General';

// Helper function to create proper heading hierarchy
function createHeadingStructure(sections) {
  let htmlContent = '';

  sections.forEach((section, index) => {
    const headingLevel = section.level || (index === 0 ? 2 : 3);
    const headingTag = `h${Math.min(headingLevel, 6)}`;

    htmlContent += `<${headingTag}>${section.heading || section.title}</${headingTag}>\n`;

    if (section.content) {
      // Split content into paragraphs
      const paragraphs = section.content.split('\n\n').filter(p => p.trim());
      paragraphs.forEach(paragraph => {
        if (paragraph.trim().startsWith('•') || paragraph.trim().startsWith('-')) {
          // Convert bullet points to unordered list
          const listItems = paragraph.split('\n').filter(item => item.trim());
          htmlContent += '<ul>\n';
          listItems.forEach(item => {
            const cleanItem = item.replace(/^[•\-]\s*/, '').trim();
            if (cleanItem) {
              htmlContent += `  <li>${cleanItem}</li>\n`;
            }
          });
          htmlContent += '</ul>\n';
        } else if (paragraph.trim().match(/^\d+\./)) {
          // Convert numbered lists to ordered list
          const listItems = paragraph.split('\n').filter(item => item.trim());
          htmlContent += '<ol>\n';
          listItems.forEach(item => {
            const cleanItem = item.replace(/^\d+\.\s*/, '').trim();
            if (cleanItem) {
              htmlContent += `  <li>${cleanItem}</li>\n`;
            }
          });
          htmlContent += '</ol>\n';
        } else {
          // Regular paragraph
          htmlContent += `<p>${paragraph.trim()}</p>\n`;
        }
      });
    }

    htmlContent += '\n';
  });

  return htmlContent;
}

// Helper function to generate meta tags
function generateMetaTags() {
  let metaTags = '';

  if (metaDescription) {
    metaTags += `<meta name="description" content="${metaDescription.replace(/"/g, '&quot;')}">\n`;
  }

  if (keywords && keywords.length > 0) {
    const keywordString = Array.isArray(keywords) ? keywords.join(', ') : keywords;
    metaTags += `<meta name="keywords" content="${keywordString}">\n`;
  }

  metaTags += `<meta name="author" content="${author}">\n`;
  metaTags += `<meta property="og:title" content="${title.replace(/"/g, '&quot;')}">\n`;

  if (metaDescription) {
    metaTags += `<meta property="og:description" content="${metaDescription.replace(/"/g, '&quot;')}">\n`;
  }

  metaTags += `<meta property="og:type" content="article">\n`;

  return metaTags;
}

// Helper function to create call-to-action section
function createCallToAction(ctaText) {
  if (!ctaText) return '';

  return `
<div class="call-to-action">
  <div class="cta-content">
    <p><strong>${ctaText}</strong></p>
  </div>
</div>
`;
}

// Generate the complete HTML structure
let htmlStructure = '';

// Add meta tags (for WordPress, these will be handled by SEO plugins)
const metaTags = generateMetaTags();

// Main content structure
htmlStructure += `<!-- SEO Meta Information -->\n`;
htmlStructure += `<!-- ${metaTags.replace(/\n/g, '\n<!-- ')} -->\n\n`;

// Article header
htmlStructure += `<article class="content-article">\n`;
htmlStructure += `  <header class="article-header">\n`;
htmlStructure += `    <h1>${title}</h1>\n`;

if (metaDescription) {
  htmlStructure += `    <div class="article-summary">\n`;
  htmlStructure += `      <p class="lead">${metaDescription}</p>\n`;
  htmlStructure += `    </div>\n`;
}

htmlStructure += `  </header>\n\n`;

// Main content
htmlStructure += `  <div class="article-content">\n`;

// Introduction paragraph if main content exists
if (content && !sections.length) {
  const paragraphs = content.split('\n\n').filter(p => p.trim());
  paragraphs.forEach(paragraph => {
    htmlStructure += `    <p>${paragraph.trim()}</p>\n`;
  });
} else if (content) {
  htmlStructure += `    <div class="article-introduction">\n`;
  htmlStructure += `      <p>${content}</p>\n`;
  htmlStructure += `    </div>\n\n`;
}

// Process sections with proper heading hierarchy
if (sections && sections.length > 0) {
  const sectionContent = createHeadingStructure(sections);
  // Indent the section content
  const indentedContent = sectionContent.split('\n').map(line => 
    line.trim() ? `    ${line}` : line
  ).join('\n');
  htmlStructure += indentedContent;
}

htmlStructure += `  </div>\n`;

// Add call-to-action if provided
if (callToAction) {
  const ctaSection = createCallToAction(callToAction);
  const indentedCta = ctaSection.split('\n').map(line => 
    line.trim() ? `  ${line}` : line
  ).join('\n');
  htmlStructure += indentedCta;
}

// Article footer with metadata
htmlStructure += `\n  <footer class="article-footer">\n`;
htmlStructure += `    <div class="article-meta">\n`;
htmlStructure += `      <span class="category">Category: ${category}</span>\n`;
if (keywords && keywords.length > 0) {
  const keywordString = Array.isArray(keywords) ? keywords.join(', ') : keywords;
  htmlStructure += `      <span class="tags">Tags: ${keywordString}</span>\n`;
}
htmlStructure += `    </div>\n`;
htmlStructure += `  </footer>\n`;
htmlStructure += `</article>`;

// Return the structured data
return {
  json: {
    ...contentData,
    htmlContent: htmlStructure,
    metaTags: metaTags,
    wordCount: htmlStructure.replace(/<[^>]*>/g, '').split(/\s+/).length,
    structuredContent: {
      title: title,
      metaDescription: metaDescription,
      keywords: keywords,
      category: category,
      author: author,
      htmlBody: htmlStructure,
      readingTime: Math.ceil(htmlStructure.replace(/<[^>]*>/g, '').split(/\s+/).length / 200)
    }
  }
};

// Topic research for blog posts
const topic = $input.first().json.topic || 'tax tips';
const keywords = $input.first().json.keywords || ['tax', 'israel', 'business'];

// Simulate topic research
const researchData = {
    topic: topic,
    keywords: keywords,
    trending: true,
    searchVolume: 'high',
    competition: 'medium',
    suggestedTitle: `Top 10 ${topic} for Israeli Businesses`,
    estimatedReadTime: '5 minutes'
};

return {
    json: {
        ...researchData,
        status: 'research_complete',
        nextStep: 'content_generation'
    }
};

// BMAD-METHOD Input Processing for Tax4US Final Agent
const input = $input.first().json;
console.log('BMAD Processing input:', input);

// Extract and validate input data
const requestData = {
  action: input.action || 'content_generation',
