  complexity: 'advanced',
  methodology: 'BMAD-UNIVERSAL-METHOD',
  version: '1.0.0',
  integrations: ['mobile-app', 'email-automation', 'content-generation'],
  nodeTypes: ['webhook', 'code', 'openai', 'microsoftOutlook', 'respondToWebhook']
};

// Generate comprehensive response data
const responseData = {
  ...requestData,
