  workflowId: 'tax4us-final-agent',
  integrations: {
    mobileApp: true,
    emailAutomation: true,
    contentGeneration: true,
    bmadValidation: true
  }
};

return { json: responseData };

// BMAD Content Analysis and Optimization
const content = $input.first().json.choices[0].message.content;
const requestData = $('BMAD Input Processing').first().json;

// Analyze content quality
const wordCount = content.split(' ').length;
const keywordAnalysis = {};
requestData.keywords.forEach(keyword => {
  const regex = new RegExp(keyword, 'gi');
  const matches = content.match(regex);
  keywordAnalysis[keyword] = matches ? matches.length : 0;
});

// Calculate SEO score
const seoScore = Math.min(100, 
  Object.values(keywordAnalysis).reduce((sum, count) => sum + count, 0) * 5 +
  (wordCount > 1000 ? 30 : 0) +
  (content.includes('Tax4US') ? 20 : 0) +
  (content.includes('Israel') ? 15 : 0)
);

// Generate meta description
const metaDescription = content.substring(0, 160).replace(/\n/g, ' ').trim() + '...';

// BMAD optimization recommendations
const recommendations = [];
if (seoScore < 80) recommendations.push('Consider adding more target keywords');
if (wordCount < 1000) recommendations.push('Expand content for better SEO');
if (!content.includes('Tax4US')) recommendations.push('Add more Tax4US brand mentions');

const analysisResult = {
  content: content,
  analysis: {
    wordCount: wordCount,
    keywordAnalysis: keywordAnalysis,
    seoScore: seoScore,
    metaDescription: metaDescription,
    recommendations: recommendations
  },
  bmad: {
