      status: "active",
      capabilities: ["airtable_integration", "workflow_triggering", "status_tracking"],
      webhook: "https://tax4usllc.app.n8n.cloud/webhook/tax4us-content-trigger",
      description: "Airtable integration and content workflow automation"
    }
  },
  system: {
    name: "Tax4Us Content Automation System",
    version: "2.0.0",
    status: "operational",
    totalAgents: 5,
    activeAgents: 5,
    lastUpdated: new Date().toISOString()
  }
};

return {
  json: {
    registry: agentRegistry,
    message: "Agent registry loaded successfully",
    timestamp: new Date().toISOString()
  }
};

// Process customer request and route to appropriate agent
const input = $input.first().json;
const registry = $('Agent Registry').item.json.registry;

// Analyze request type
const requestType = input.request_type || 'info';
const targetAgent = input.target_agent;
const requestData = input.request_data || {};

let response = {
  requestType: requestType,
  targetAgent: targetAgent,
  requestData: requestData,
  timestamp: new Date().toISOString(),
  status: 'processing'
};

// Route based on request type
switch (requestType) {
  case 'agent_info':
    if (targetAgent && registry.agents[targetAgent]) {
      response.result = registry.agents[targetAgent];
      response.message = `Information for ${registry.agents[targetAgent].name}`;
    } else {
      response.result = registry;
      response.message = 'Complete agent registry information';
    }
    break;

  case 'content_creation':
    if (targetAgent === 'blog_posts') {
      response.routeTo = 'blog_posts';
      response.webhook = registry.agents.blog_posts.webhook;
      response.message = 'Routing to Blog & Posts Agent';
    } else if (targetAgent === 'podcast') {
      response.routeTo = 'podcast';
      response.webhook = registry.agents.podcast.webhook;
      response.message = 'Routing to Podcast Agent';
    } else if (targetAgent === 'social_media') {
      response.routeTo = 'social_media';
      response.webhook = registry.agents.social_media.webhook;
      response.message = 'Routing to Social Media Agent';
    } else {
      response.error = 'Invalid target agent for content creation';
      response.availableAgents = ['blog_posts', 'podcast', 'social_media'];
    }
    break;

  case 'content_research':
    response.routeTo = 'content_intelligence';
    response.webhook = registry.agents.content_intelligence.webhook;
    response.message = 'Routing to Content Intelligence Agent';
    break;

  case 'system_status':
    response.result = registry.system;
    response.message = 'Tax4Us Content Automation System Status';
    break;

  default:
    response.error = 'Unknown request type';
    response.availableTypes = ['agent_info', 'content_creation', 'content_research', 'system_status'];
}

return {
  json: response
};

// Execute agent request if routing is needed
const routingInfo = $input.first().json;

if (routingInfo.routeTo && routingInfo.webhook) {
  // Simulate agent execution
  const executionResult = {
    agent: routingInfo.routeTo,
    webhook: routingInfo.webhook,
    requestData: routingInfo.requestData,
    status: 'executed',
    timestamp: new Date().toISOString(),
    message: `Request successfully routed to ${routingInfo.routeTo}`
  };

  return {
    json: {
      ...routingInfo,
      execution: executionResult,
      message: `Request processed by ${routingInfo.routeTo} agent`
    }
  };
} else {
  // No routing needed, return direct response
  return {
    json: {
      ...routingInfo,
      message: routingInfo.message || 'Request processed successfully'
    }
  };
}

// Log orchestration results
const results = $input.all();
console.log('Tax4Us Orchestration Agent Results:');

let summary = {
  request: $('Request Router').item.json,
  execution: $('Agent Executor').item.json,
  registry: $('Agent Registry').item.json.registry,
  timestamp: new Date().toISOString()
};

console.log('✅ Orchestration request processed successfully!');
console.log(`🎯 Request Type: ${summary.request.requestType}`);
console.log(`🤖 Target Agent: ${summary.request.targetAgent || 'N/A'}`);
console.log(`📊 System Status: ${summary.registry.system.status}`);

return {
  json: {
    message: 'Tax4Us Orchestration Agent processed request successfully!',
    summary,
    status: 'success',
    nextSteps: [
      'Request routed to appropriate agent',
      'Agent execution completed',
      'System status updated',
      'Ready for next orchestration request'
    ]
  }
};

// Tax4Us Social Media Agent - Input Processing
const input = $input.first().json;

// Validate required fields
const required = ['platform', 'content_type', 'topic'];
const missing = required.filter(field => !input[field]);
if (missing.length > 0) {
  throw new Error('Missing required fields: ' + missing.join(', '));
}

